mapper.select:
SELECT trip_place_id
FROM trip_place
WHERE place_name = #{placeName}
  AND address    = #{address}
  AND ROWNUM = 1

SELECT * FROM ( SELECT trip_place_id AS placeId, member_id AS memberId, api_place_id AS apiContentId, place_name AS placeName, address, latitude, longitude, category_name AS category, place_url AS imageUrl, 0 AS isCustom FROM trip_place WHERE member_id IS NULL
AND (
address LIKE '%' || #{city} || '%'
)
AND category_name = #{category}
ORDER BY DBMS_RANDOM.VALUE ) WHERE ROWNUM <= #{limit}
